head.b:skin:
:root {
  --bg: #0b0f1a; --bg2: #111827; --s1: #1a2234; --s2: #1e2a3e; --s3: #243147; --s4: #2c3d58;
  --br: #2e3f5c; --br2: #3a4f6e; --a: #3b82f6; --a2: #6366f1; --a3: #22d3ee;
  --g: #10b981; --r: #ef4444; --y: #f59e0b;
  --tx: #e8edf5; --t2: #94a3b8; --t3: #4a6080; --t4: #2d3d55;
  --grad: linear-gradient(135deg, #3b82f6 0%, #6366f1 50%, #22d3ee 100%);
  --card-shadow: 0 4px 24px rgba(0,0,0,.4); --nav-h: 64px;
  --font-display: 'Syne', sans-serif; --font-body: 'DM Sans', sans-serif;
  --radius: 12px; --radius-lg: 18px; --radius-xl: 24px;
  --transition: all .2s cubic-bezier(.4,0,.2,1);
}
body.light-mode {
  --bg: #f0f4f8; --bg2: #ffffff; --s1: #ffffff; --s2: #f5f8fc; --s3: #edf2f7; --s4: #e2e8f0;
  --br: #d1dce9; --br2: #bac8d8; --a: #2563eb; --a2: #4f46e5; --a3: #0891b2;
  --tx: #0f1f36; --t2: #334e68; --t3: #627d98; --t4: #9fb3c8;
  --card-shadow: 0 4px 20px rgba(0,0,0,.08);
}
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; }
body { font-family: var(--font-body); background: var(--bg); color: var(--tx); font-size: 15px; line-height: 1.65; -webkit-font-smoothing: antialiased; overflow-x: hidden; }
a { color: var(--a); text-decoration: none; transition: var(--transition); }
a:hover { color: var(--a3); }
img { max-width: 100%; height: auto; }
::-webkit-scrollbar { width: 5px; }
::-webkit-scrollbar-track { background: var(--bg); }
::-webkit-scrollbar-thumb { background: var(--br2); border-radius: 3px; }
.container { max-width: 1200px; margin: 0 auto; padding: 0 20px; }
.container-sm { max-width: 860px; margin: 0 auto; padding: 0 20px; }
.btn { display: inline-flex; align-items: center; gap: 7px; padding: 10px 22px; border-radius: 50px; font-family: var(--font-body); font-size: 14px; font-weight: 600; cursor: pointer; transition: var(--transition); border: none; white-space: nowrap; text-decoration: none; }
.btn-primary { background: var(--a); color: #fff; box-shadow: 0 4px 16px rgba(59,130,246,.35); }
.btn-primary:hover { background: var(--a2); transform: translateY(-2px); box-shadow: 0 8px 24px rgba(59,130,246,.45); color: #fff; }
.btn-outline { background: transparent; color: var(--tx); border: 1.5px solid var(--br2); }
.btn-outline:hover { border-color: var(--a); color: var(--a); }
.tag { display: inline-flex; align-items: center; gap: 4px; padding: 3px 11px; border-radius: 50px; font-size: 11px; font-weight: 700; letter-spacing: .4px; }
#lp-header { position: sticky; top: 0; z-index: 1000; height: var(--nav-h); background: rgba(11,15,26,.92); backdrop-filter: blur(18px) saturate(180%); -webkit-backdrop-filter: blur(18px) saturate(180%); border-bottom: 1px solid rgba(255,255,255,.06); transition: var(--transition); }
body.light-mode #lp-header { background: rgba(255,255,255,.92); border-bottom-color: rgba(0,0,0,.07); }
.header-inner { display: flex; align-items: center; height: var(--nav-h); gap: 0; }
.lp-logo { display: flex; align-items: center; gap: 10px; text-decoration: none; flex-shrink: 0; }
.lp-logo-icon { width: 38px; height: 38px; border-radius: 11px; background: linear-gradient(135deg,#1e40af,#312e81); border: 1px solid rgba(99,102,241,.35); display: flex; align-items: center; justify-content: center; font-size: 18px; box-shadow: 0 2px 12px rgba(59,130,246,.3); }
.lp-logo-text { font-family: var(--font-display); font-size: 19px; font-weight: 800; letter-spacing: -.5px; background: var(--grad); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; line-height: 1; }
.lp-nav { flex: 1; display: flex; align-items: center; justify-content: center; gap: 4px; }
.nav-item { position: relative; }
.nav-link { display: flex; align-items: center; gap: 5px; padding: 8px 14px; border-radius: 9px; font-size: 14px; font-weight: 500; color: var(--t2); text-decoration: none; white-space: nowrap; transition: var(--transition); }
.nav-link svg { transition: transform .2s; width: 12px; height: 12px; fill: none; stroke: currentColor; stroke-width: 2.5; }
.nav-link:hover { color: var(--tx); background: var(--s3); }
.nav-item:hover > .nav-link { color: var(--a); }
.nav-item:hover > .nav-link svg { transform: rotate(180deg); }
.nav-dropdown { position: absolute; top: calc(100% + 10px); left: 50%; transform: translateX(-50%) translateY(8px); background: var(--s1); border: 1px solid var(--br2); border-radius: var(--radius-lg); padding: 8px; min-width: 220px; max-width: 640px; box-shadow: 0 20px 60px rgba(0,0,0,.5),0 4px 16px rgba(0,0,0,.2); opacity: 0; visibility: hidden; pointer-events: none; transition: all .22s cubic-bezier(.4,0,.2,1); z-index: 500; }
.nav-item:hover .nav-dropdown { opacity: 1; visibility: visible; pointer-events: auto; transform: translateX(-50%) translateY(0); }
.nav-dropdown.wide { min-width: 520px; }
.nav-dropdown.grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 4px; }
.nav-dropdown.grid-3 { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 4px; }
.dd-item { display: flex; align-items: center; gap: 10px; padding: 10px 12px; border-radius: 10px; text-decoration: none; color: var(--t2); transition: var(--transition); cursor: pointer; }
.dd-item:hover { background: var(--s3); color: var(--tx); }
.dd-icon { width: 36px; height: 36px; border-radius: 10px; flex-shrink: 0; display: flex; align-items: center; justify-content: center; font-size: 17px; }
.dd-texts { flex: 1; min-width: 0; }
.dd-name { font-size: 13px; font-weight: 600; color: var(--tx); line-height: 1.2; }
.dd-desc { font-size: 11px; color: var(--t3); margin-top: 1px; }
.dd-sep { grid-column: 1/-1; height: 1px; background: var(--br); margin: 4px 0; }
.dd-header { grid-column: 1/-1; padding: 6px 12px 4px; font-size: 10px; font-weight: 800; letter-spacing: 1.5px; text-transform: uppercase; color: var(--t3); display: flex; align-items: center; gap: 6px; }
.dd-header::after { content: ''; flex: 1; height: 1px; background: var(--br); }
.header-right { display: flex; align-items: center; gap: 8px; flex-shrink: 0; }
.header-search { display: flex; align-items: center; gap: 7px; padding: 7px 14px; border-radius: 50px; background: var(--s3); border: 1px solid var(--br); color: var(--t2); font-size: 13px; cursor: pointer; transition: var(--transition); }
.header-search:hover { border-color: var(--a); color: var(--a); }
.theme-btn { width: 36px; height: 36px; border-radius: 10px; background: var(--s3); border: 1px solid var(--br); color: var(--t2); cursor: pointer; display: flex; align-items: center; justify-content: center; font-size: 16px; transition: var(--transition); }
.theme-btn:hover { border-color: var(--a); color: var(--a); }
.header-cta { background: linear-gradient(135deg,var(--a),var(--a2)); color: #fff; padding: 8px 18px; border-radius: 50px; font-size: 13px; font-weight: 700; text-decoration: none; box-shadow: 0 4px 14px rgba(59,130,246,.3); transition: var(--transition); }
.header-cta:hover { transform: translateY(-1px); box-shadow: 0 6px 20px rgba(59,130,246,.45); color: #fff; }
.mobile-menu-btn { display: none; width: 36px; height: 36px; border-radius: 10px; background: var(--s3); border: 1px solid var(--br); color: var(--t2); cursor: pointer; align-items: center; justify-content: center; flex-direction: column; gap: 5px; }
.mobile-menu-btn span { display: block; width: 18px; height: 2px; background: currentColor; border-radius: 2px; transition: var(--transition); }
.mobile-nav { display: none; position: fixed; inset: 0; z-index: 1500; background: rgba(0,0,0,.8); backdrop-filter: blur(10px); }
.mobile-nav.open { display: flex; }
.mobile-nav-inner { width: min(340px,90vw); height: 100%; background: var(--s1); border-right: 1px solid var(--br2); overflow-y: auto; padding: 0 0 40px; animation: slideInLeft .28s cubic-bezier(.4,0,.2,1); }
@keyframes slideInLeft { from { transform: translateX(-100%); } to { transform: translateX(0); } }
.mobile-nav-head { display: flex; align-items: center; justify-content: space-between; padding: 16px 18px; border-bottom: 1px solid var(--br); }
.mobile-close { width: 32px; height: 32px; border-radius: 50%; background: var(--s3); border: 1px solid var(--br); color: var(--t2); cursor: pointer; display: flex; align-items: center; justify-content: center; font-size: 15px; }
.mobile-menu-list { padding: 10px 0; }
.mobile-menu-section { font-size: 9px; font-weight: 800; letter-spacing: 1.6px; text-transform: uppercase; color: var(--t3); padding: 12px 20px 5px; }
.mobile-menu-item { display: flex; align-items: center; gap: 12px; padding: 11px 20px; font-size: 14px; color: var(--t2); text-decoration: none; transition: background .15s; }
.mobile-menu-item:hover { background: var(--s3); color: var(--tx); }
.mobile-menu-icon { width: 34px; height: 34px; border-radius: 9px; flex-shrink: 0; display: flex; align-items: center; justify-content: center; font-size: 16px; }
.mobile-menu-divider { height: 1px; background: var(--br); margin: 8px 0; }
.lp-hero { position: relative; overflow: hidden; padding: 90px 0 80px; background: var(--bg2); }
.hero-bg { position: absolute; inset: 0; pointer-events: none; background: radial-gradient(ellipse at 20% 30%,rgba(59,130,246,.18) 0,transparent 55%), radial-gradient(ellipse at 80% 70%,rgba(99,102,241,.14) 0,transparent 50%), radial-gradient(ellipse at 60% 10%,rgba(34,211,238,.1) 0,transparent 40%); }
body.light-mode .hero-bg { background: radial-gradient(ellipse at 20% 30%,rgba(37,99,235,.08) 0,transparent 55%), radial-gradient(ellipse at 80% 70%,rgba(79,70,229,.06) 0,transparent 50%); }
.hero-grid-dots { position: absolute; inset: 0; pointer-events: none; opacity: .3; background-image: radial-gradient(circle,var(--br) 1px,transparent 1px); background-size: 28px 28px; }
body.light-mode .hero-grid-dots { opacity: .15; }
.hero-content { position: relative; z-index: 1; text-align: center; }
.hero-badge { display: inline-flex; align-items: center; gap: 7px; padding: 6px 16px; border-radius: 50px; background: rgba(59,130,246,.1); border: 1px solid rgba(59,130,246,.25); font-size: 12px; font-weight: 700; color: #60a5fa; letter-spacing: .3px; margin-bottom: 22px; animation: fadeUp .5s .1s both; }
.hero-title { font-family: var(--font-display); font-size: clamp(34px,6vw,60px); font-weight: 800; letter-spacing: -1.5px; line-height: 1.1; color: var(--tx); margin-bottom: 18px; animation: fadeUp .6s .2s both; }
.hero-title .gradient-text { background: var(--grad); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
.hero-sub { font-size: 17px; color: var(--t2); max-width: 560px; margin: 0 auto 36px; line-height: 1.7; animation: fadeUp .6s .3s both; }
.hero-search { max-width: 560px; margin: 0 auto; position: relative; animation: fadeUp .6s .4s both; }
.hero-search-box { display: flex; align-items: center; gap: 0; background: var(--s1); border: 1.5px solid var(--br2); border-radius: 50px; padding: 6px 6px 6px 20px; box-shadow: 0 8px 40px rgba(0,0,0,.25),0 0 0 1px rgba(255,255,255,.04); transition: border-color .2s,box-shadow .2s; }
.hero-search-box:focus-within { border-color: var(--a); box-shadow: 0 8px 40px rgba(0,0,0,.25),0 0 0 4px rgba(59,130,246,.15); }
.hero-search-icon { font-size: 18px; flex-shrink: 0; }
.hero-search-input { flex: 1; background: transparent; border: none; outline: none; font-family: var(--font-body); font-size: 15px; color: var(--tx); padding: 8px 14px; }
.hero-search-input::placeholder { color: var(--t3); }
.hero-search-btn { padding: 10px 22px; border-radius: 50px; background: var(--a); color: #fff; border: none; font-size: 14px; font-weight: 700; cursor: pointer; transition: var(--transition); flex-shrink: 0; }
.hero-search-btn:hover { background: var(--a2); transform: scale(1.03); }
.hero-stats { display: flex; align-items: center; justify-content: center; gap: 32px; margin-top: 40px; animation: fadeUp .6s .5s both; flex-wrap: wrap; }
.hero-stat { text-align: center; }
.hero-stat-val { font-family: var(--font-display); font-size: 24px; font-weight: 800; color: var(--tx); line-height: 1; background: var(--grad); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
.hero-stat-lbl { font-size: 12px; color: var(--t3); margin-top: 3px; }
.hero-stat-sep { width: 1px; height: 36px; background: var(--br); }
@keyframes fadeUp { from { opacity: 0; transform: translateY(18px); } to { opacity: 1; transform: translateY(0); } }
.tools-section { padding: 72px 0 80px; }
.section-header { text-align: center; margin-bottom: 48px; }
.section-tag { display: inline-flex; align-items: center; gap: 6px; padding: 5px 14px; border-radius: 50px; background: rgba(34,211,238,.1); border: 1px solid rgba(34,211,238,.25); font-size: 11px; font-weight: 700; color: var(--a3); letter-spacing: .5px; text-transform: uppercase; margin-bottom: 12px; }
.section-title { font-family: var(--font-display); font-size: clamp(26px,4vw,40px); font-weight: 800; letter-spacing: -1px; color: var(--tx); line-height: 1.15; margin-bottom: 12px; }
.section-sub { font-size: 16px; color: var(--t2); max-width: 500px; margin: 0 auto; }
.tools-categories { display: flex; flex-direction: column; gap: 52px; }
.tool-cat-head { display: flex; align-items: center; gap: 12px; margin-bottom: 18px; padding-bottom: 14px; border-bottom: 1px solid var(--br); }
.tool-cat-icon { width: 38px; height: 38px; border-radius: 11px; display: flex; align-items: center; justify-content: center; font-size: 18px; flex-shrink: 0; }
.tool-cat-title { font-family: var(--font-display); font-size: 18px; font-weight: 700; color: var(--tx); letter-spacing: -.3px; }
.tool-cat-count { margin-left: auto; font-size: 11px; font-weight: 700; padding: 3px 10px; border-radius: 50px; background: var(--s3); color: var(--t3); border: 1px solid var(--br); }
.tool-cat-see-all { display: flex; align-items: center; gap: 5px; font-size: 13px; font-weight: 600; color: var(--a); text-decoration: none; margin-left: 12px; flex-shrink: 0; transition: var(--transition); }
.tool-cat-see-all:hover { gap: 8px; }
.tools-grid { display: grid; grid-template-columns: repeat(auto-fill,minmax(200px,1fr)); gap: 12px; }
.tool-card { display: flex; flex-direction: column; gap: 8px; padding: 16px 14px; border-radius: var(--radius); background: var(--s1); border: 1px solid var(--br); text-decoration: none; color: var(--t2); transition: all .22s cubic-bezier(.34,1.2,.64,1); cursor: pointer; position: relative; overflow: hidden; }
.tool-card::before { content: ''; position: absolute; inset: 0; opacity: 0; background: linear-gradient(135deg,rgba(59,130,246,.06),transparent); transition: opacity .2s; }
.tool-card:hover { border-color: var(--a); background: var(--s2); transform: translateY(-3px); box-shadow: var(--card-shadow); color: var(--tx); }
.tool-card:hover::before { opacity: 1; }
.tool-card:active { transform: scale(.97); }
.tc-icon { width: 44px; height: 44px; border-radius: 12px; display: flex; align-items: center; justify-content: center; font-size: 20px; border: 1px solid; flex-shrink: 0; }
.tc-name { font-size: 13px; font-weight: 700; color: var(--tx); line-height: 1.25; }
.tc-desc { font-size: 11px; color: var(--t3); line-height: 1.4; }
.tc-badge { display: inline-flex; align-items: center; padding: 2px 8px; border-radius: 50px; font-size: 9px; font-weight: 800; letter-spacing: .5px; text-transform: uppercase; }
.features-section { padding: 80px 0; background: var(--bg2); border-top: 1px solid var(--br); border-bottom: 1px solid var(--br); }
.features-grid { display: grid; grid-template-columns: repeat(auto-fit,minmax(220px,1fr)); gap: 24px; }
.feature-card { padding: 24px 20px; border-radius: var(--radius-lg); background: var(--s1); border: 1px solid var(--br); transition: var(--transition); }
.feature-card:hover { border-color: var(--br2); box-shadow: var(--card-shadow); transform: translateY(-2px); }
.feature-icon { width: 52px; height: 52px; border-radius: 14px; background: linear-gradient(135deg,rgba(59,130,246,.15),rgba(99,102,241,.1)); border: 1px solid rgba(59,130,246,.2); display: flex; align-items: center; justify-content: center; font-size: 22px; margin-bottom: 16px; }
.feature-title { font-family: var(--font-display); font-size: 16px; font-weight: 700; color: var(--tx); margin-bottom: 7px; letter-spacing: -.2px; }
.feature-desc { font-size: 13px; color: var(--t2); line-height: 1.65; }
.blog-section { padding: 80px 0; }
.blog-layout { display: grid; grid-template-columns: 1fr 320px; gap: 36px; }
.posts-list { display: flex; flex-direction: column; gap: 24px; }
.post-card { background: var(--s1); border: 1px solid var(--br); border-radius: var(--radius-lg); overflow: hidden; transition: var(--transition); }
.post-card:hover { border-color: var(--br2); box-shadow: var(--card-shadow); transform: translateY(-2px); }
.post-card-img { width: 100%; height: 200px; object-fit: cover; background: var(--s3); display: flex; align-items: center; justify-content: center; font-size: 40px; }
.post-card-img img { width: 100%; height: 200px; object-fit: cover; }
.post-card-body { padding: 22px 22px 20px; }
.post-card-tags { display: flex; gap: 7px; margin-bottom: 12px; flex-wrap: wrap; }
.post-card-tag { padding: 3px 11px; border-radius: 50px; font-size: 10px; font-weight: 700; text-transform: uppercase; letter-spacing: .5px; background: rgba(59,130,246,.1); border: 1px solid rgba(59,130,246,.2); color: #60a5fa; }
.post-card-title { font-family: var(--font-display); font-size: 19px; font-weight: 700; color: var(--tx); letter-spacing: -.3px; line-height: 1.3; margin-bottom: 10px; }
.post-card-title a { color: var(--tx); text-decoration: none; }
.post-card-title a:hover { color: var(--a); }
.post-card-excerpt { font-size: 14px; color: var(--t2); line-height: 1.7; margin-bottom: 16px; }
.post-card-meta { display: flex; align-items: center; gap: 14px; font-size: 12px; color: var(--t3); padding-top: 16px; border-top: 1px solid var(--br); flex-wrap: wrap; }
.post-meta-item { display: flex; align-items: center; gap: 5px; }
.post-read-more { margin-left: auto; font-size: 13px; font-weight: 600; color: var(--a); text-decoration: none; display: flex; align-items: center; gap: 4px; transition: gap .15s; }
.post-read-more:hover { gap: 7px; }
.post-single { max-width: 760px; }
.post-single-header { margin-bottom: 32px; }
.post-single-title { font-family: var(--font-display); font-size: clamp(26px,4vw,40px); font-weight: 800; letter-spacing: -1px; color: var(--tx); line-height: 1.15; margin-bottom: 16px; }
.post-single-meta { display: flex; align-items: center; gap: 16px; font-size: 13px; color: var(--t3); flex-wrap: wrap; padding-bottom: 20px; border-bottom: 1px solid var(--br); }
.post-single-img { width: 100%; border-radius: var(--radius-lg); overflow: hidden; margin: 24px 0; border: 1px solid var(--br); }
.post-single-img img { width: 100%; display: block; }
.post-content { font-size: 16px; line-height: 1.85; color: var(--t2); }
.post-content h1,.post-content h2,.post-content h3,.post-content h4,.post-content h5 { font-family: var(--font-display); color: var(--tx); margin: 32px 0 14px; font-weight: 700; letter-spacing: -.3px; line-height: 1.2; }
.post-content h2 { font-size: 26px; } .post-content h3 { font-size: 21px; }
.post-content p { margin-bottom: 18px; }
.post-content a { color: var(--a); border-bottom: 1px solid rgba(59,130,246,.3); }
.post-content a:hover { border-bottom-color: var(--a); }
.post-content ul,.post-content ol { margin: 0 0 18px 22px; }
.post-content li { margin-bottom: 7px; }
.post-content blockquote { margin: 24px 0; padding: 18px 22px; border-left: 4px solid var(--a); background: rgba(59,130,246,.06); border-radius: 0 var(--radius) var(--radius) 0; font-style: italic; color: var(--t2); }
.post-content code { background: var(--s3); padding: 2px 7px; border-radius: 5px; font-size: 13px; color: var(--a3); }
.post-content pre { background: var(--s2); border: 1px solid var(--br); border-radius: var(--radius); padding: 18px; overflow-x: auto; margin: 24px 0; }
.post-content pre code { background: none; padding: 0; }
.post-content img { max-width: 100%; border-radius: var(--radius); margin: 18px 0; }
.post-content table { width: 100%; border-collapse: collapse; margin: 24px 0; font-size: 14px; }
.post-content th,.post-content td { padding: 12px 16px; border: 1px solid var(--br); text-align: left; }
.post-content th { background: var(--s3); font-weight: 700; color: var(--tx); }
.tool-embed-widget { width: 100%; border-radius: var(--radius-lg); border: 2px solid var(--br2); overflow: hidden; background: var(--s1); margin: 32px 0; box-shadow: var(--card-shadow); }
.tool-embed-header { display: flex; align-items: center; gap: 12px; padding: 14px 18px; background: var(--s2); border-bottom: 1px solid var(--br); }
.tool-embed-icon { width: 38px; height: 38px; border-radius: 10px; background: rgba(59,130,246,.12); border: 1px solid rgba(59,130,246,.25); display: flex; align-items: center; justify-content: center; font-size: 18px; }
.tool-embed-title { font-size: 14px; font-weight: 700; color: var(--tx); }
.tool-embed-frame { width: 100%; border: none; min-height: 600px; display: block; }
.tool-embed-cta { display: flex; align-items: center; justify-content: space-between; padding: 14px 18px; background: rgba(59,130,246,.05); border-top: 1px solid var(--br); font-size: 13px; color: var(--t2); }
.sidebar { position: sticky; top: calc(var(--nav-h) + 20px); }
.sidebar-widget { background: var(--s1); border: 1px solid var(--br); border-radius: var(--radius-lg); overflow: hidden; margin-bottom: 20px; }
.sw-header { padding: 14px 18px; border-bottom: 1px solid var(--br); font-family: var(--font-display); font-size: 14px; font-weight: 700; color: var(--tx); display: flex; align-items: center; gap: 8px; }
.sw-header::before { content: ''; width: 3px; height: 14px; background: var(--a); border-radius: 2px; }
.sw-body { padding: 14px 18px; }
.sidebar-tool-list { display: flex; flex-direction: column; gap: 4px; }
.sidebar-tool-item { display: flex; align-items: center; gap: 10px; padding: 9px 12px; border-radius: 10px; cursor: pointer; transition: background .15s; text-decoration: none; color: var(--t2); }
.sidebar-tool-item:hover { background: var(--s3); color: var(--tx); }
.st-icon { width: 32px; height: 32px; border-radius: 9px; display: flex; align-items: center; justify-content: center; font-size: 16px; flex-shrink: 0; }
.st-name { font-size: 13px; font-weight: 600; }
.cta-section { padding: 80px 0; background: var(--bg2); border-top: 1px solid var(--br); }
.cta-card { border-radius: var(--radius-xl); background: linear-gradient(135deg,#1e3a8a 0%,#312e81 40%,#1e1b4b 100%); border: 1px solid rgba(255,255,255,.1); padding: 60px 40px; text-align: center; position: relative; overflow: hidden; }
.cta-card::before { content: ''; position: absolute; inset: 0; background: radial-gradient(ellipse at 30% 50%,rgba(99,102,241,.3),transparent 60%), radial-gradient(ellipse at 70% 50%,rgba(34,211,238,.15),transparent 60%); }
.cta-card-content { position: relative; z-index: 1; }
.cta-title { font-family: var(--font-display); font-size: clamp(26px,4vw,40px); font-weight: 800; color: #fff; letter-spacing: -1px; margin-bottom: 14px; }
.cta-sub { font-size: 16px; color: rgba(255,255,255,.65); max-width: 480px; margin: 0 auto 30px; line-height: 1.6; }
.cta-btns { display: flex; gap: 12px; justify-content: center; flex-wrap: wrap; }
.cta-btn-primary { padding: 13px 28px; border-radius: 50px; background: linear-gradient(135deg,#60a5fa,#818cf8); color: #fff; font-weight: 700; font-size: 15px; text-decoration: none; box-shadow: 0 6px 24px rgba(96,165,250,.4); transition: var(--transition); display: inline-flex; align-items: center; gap: 7px; }
.cta-btn-primary:hover { transform: translateY(-2px); box-shadow: 0 10px 32px rgba(96,165,250,.55); color: #fff; }
.cta-btn-secondary { padding: 13px 24px; border-radius: 50px; background: rgba(255,255,255,.1); border: 1.5px solid rgba(255,255,255,.25); color: rgba(255,255,255,.85); font-weight: 600; font-size: 15px; text-decoration: none; transition: var(--transition); display: inline-flex; align-items: center; gap: 7px; }
.cta-btn-secondary:hover { background: rgba(255,255,255,.18); color: #fff; }
.pagination { display: flex; align-items: center; justify-content: center; gap: 6px; padding: 48px 0 0; flex-wrap: wrap; }
.page-link,.page-current { width: 40px; height: 40px; border-radius: 10px; display: flex; align-items: center; justify-content: center; font-size: 14px; font-weight: 600; text-decoration: none; transition: var(--transition); }
.page-link { background: var(--s1); border: 1px solid var(--br); color: var(--t2); }
.page-link:hover { border-color: var(--a); color: var(--a); background: var(--s3); }
.page-current { background: var(--a); color: #fff; border: 1px solid transparent; box-shadow: 0 4px 14px rgba(59,130,246,.35); }
.page-prev,.page-next { padding: 0 16px; width: auto; gap: 6px; background: var(--s1); border: 1px solid var(--br); color: var(--t2); }
.page-prev:hover,.page-next:hover { color: var(--a); border-color: var(--a); }
.lp-breadcrumb { padding: 14px 0; font-size: 13px; color: var(--t3); display: flex; align-items: center; gap: 7px; flex-wrap: wrap; }
.lp-breadcrumb a { color: var(--t3); text-decoration: none; }
.lp-breadcrumb a:hover { color: var(--a); }
.lp-breadcrumb .bc-sep { color: var(--t4); }
.lp-breadcrumb .bc-current { color: var(--t2); font-weight: 500; }
.labels-cloud { display: flex; flex-wrap: wrap; gap: 7px; }
.label-link { display: inline-flex; align-items: center; gap: 5px; padding: 5px 13px; border-radius: 50px; font-size: 12px; font-weight: 600; color: var(--t2); background: var(--s3); border: 1px solid var(--br); text-decoration: none; transition: var(--transition); }
.label-link:hover { border-color: var(--a); color: var(--a); background: rgba(59,130,246,.08); }
#lp-footer { background: var(--bg2); border-top: 1px solid var(--br); padding: 64px 0 0; }
.footer-grid { display: grid; grid-template-columns: 280px repeat(3,1fr); gap: 40px; margin-bottom: 48px; }
.footer-logo-wrap { display: flex; align-items: center; gap: 10px; margin-bottom: 14px; }
.footer-logo-icon { width: 36px; height: 36px; border-radius: 10px; background: linear-gradient(135deg,#1e40af,#312e81); border: 1px solid rgba(99,102,241,.35); display: flex; align-items: center; justify-content: center; font-size: 17px; }
.footer-logo-text { font-family: var(--font-display); font-size: 18px; font-weight: 800; background: var(--grad); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
.footer-desc { font-size: 13px; color: var(--t3); line-height: 1.75; margin-bottom: 20px; }
.footer-social { display: flex; gap: 8px; }
.social-btn { width: 36px; height: 36px; border-radius: 9px; background: var(--s3); border: 1px solid var(--br); display: flex; align-items: center; justify-content: center; font-size: 15px; text-decoration: none; color: var(--t2); transition: var(--transition); }
.social-btn:hover { border-color: var(--a); color: var(--a); background: rgba(59,130,246,.08); }
.footer-col-title { font-size: 12px; font-weight: 800; letter-spacing: 1.5px; text-transform: uppercase; color: var(--t2); margin-bottom: 16px; }
.footer-links { display: flex; flex-direction: column; gap: 9px; }
.footer-link { font-size: 13px; color: var(--t3); text-decoration: none; transition: var(--transition); }
.footer-link:hover { color: var(--tx); padding-left: 3px; }
.footer-bottom { border-top: 1px solid var(--br); padding: 20px 0; display: flex; align-items: center; justify-content: space-between; font-size: 12px; color: var(--t3); flex-wrap: wrap; gap: 12px; }
.footer-bottom-links { display: flex; gap: 20px; }
.footer-bottom-links a { color: var(--t3); text-decoration: none; }
.footer-bottom-links a:hover { color: var(--tx); }
.announcement-bar { background: linear-gradient(135deg,#1d4ed8,#4f46e5); padding: 10px 0; text-align: center; font-size: 13px; color: rgba(255,255,255,.9); font-weight: 500; }
.announcement-bar a { color: #fff; text-decoration: underline; font-weight: 700; }
.search-overlay { display: none; position: fixed; inset: 0; z-index: 2000; background: rgba(0,0,0,.8); backdrop-filter: blur(12px); align-items: flex-start; justify-content: center; padding-top: 80px; }
.search-overlay.open { display: flex; animation: fadeIn .2s ease; }
.search-box-overlay { width: min(620px,calc(100% - 40px)); background: var(--s1); border: 1px solid var(--br2); border-radius: var(--radius-xl); overflow: hidden; box-shadow: 0 30px 80px rgba(0,0,0,.6); }
.search-input-row { display: flex; align-items: center; gap: 0; padding: 0 20px; border-bottom: 1px solid var(--br); }
.search-input-row .si { font-size: 20px; flex-shrink: 0; }
.search-input-field { flex: 1; padding: 18px 14px; background: transparent; border: none; outline: none; font-size: 17px; color: var(--tx); font-family: var(--font-body); }
.search-input-field::placeholder { color: var(--t3); }
.search-close-btn { width: 32px; height: 32px; border-radius: 8px; background: var(--s3); border: 1px solid var(--br); color: var(--t2); cursor: pointer; display: flex; align-items: center; justify-content: center; font-size: 13px; flex-shrink: 0; }
.search-hints { padding: 16px 20px; font-size: 12px; color: var(--t3); display: flex; gap: 10px; flex-wrap: wrap; align-items: center; }
.search-hint-tag { padding: 4px 11px; border-radius: 50px; background: var(--s3); border: 1px solid var(--br); color: var(--t2); cursor: pointer; font-size: 12px; font-weight: 500; transition: var(--transition); }
.search-hint-tag:hover { border-color: var(--a); color: var(--a); }
@keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
.notice { padding: 14px 18px; border-radius: var(--radius); display: flex; align-items: flex-start; gap: 12px; margin: 20px 0; font-size: 13px; line-height: 1.65; }
.notice-info { background: rgba(59,130,246,.08); border: 1px solid rgba(59,130,246,.2); color: var(--t2); }
.notice-success { background: rgba(16,185,129,.08); border: 1px solid rgba(16,185,129,.2); color: var(--t2); }
.notice-warning { background: rgba(245,158,11,.08); border: 1px solid rgba(245,158,11,.2); color: var(--t2); }
.notice-icon { font-size: 17px; flex-shrink: 0; margin-top: 1px; }

/* === Professional Motion System === */
:root{--motion-fast:.22s;--motion-base:.38s;--motion-slow:.65s;--ease-pro:cubic-bezier(.22,1,.36,1);}
#lp-header,.hero-search-box,.feature-card,.post-card,.cta-card,.sidebar-widget,.search-box-overlay,.header-cta,.theme-btn,.header-search,.social-btn,.footer-link,.label-link,.page-link,.page-prev,.page-next{
  transition:transform var(--motion-base) var(--ease-pro),box-shadow var(--motion-base) var(--ease-pro),border-color var(--motion-fast) ease,background-color var(--motion-fast) ease,color var(--motion-fast) ease,opacity var(--motion-base) ease;
}
#lp-header.is-scrolled{box-shadow:0 10px 30px rgba(0,0,0,.18);}
body.light-mode #lp-header.is-scrolled{box-shadow:0 10px 30px rgba(15,23,42,.08);}
.lp-logo-icon,.tool-cat-icon,.feature-icon,.footer-logo-icon{animation:floatSoft 6s ease-in-out infinite;}
.hero-badge{animation:fadeUp .55s .08s both, glowPulse 3.5s ease-in-out 1.2s infinite;}
.hero-search-box:hover{transform:translateY(-2px);box-shadow:0 14px 44px rgba(0,0,0,.28),0 0 0 1px rgba(255,255,255,.04);}
.feature-card:hover,.post-card:hover,.sidebar-widget:hover{transform:translateY(-6px);box-shadow:0 18px 42px rgba(0,0,0,.22);}
.cta-card:hover{transform:translateY(-4px);box-shadow:0 22px 60px rgba(0,0,0,.24);}
.footer-link,.label-link,.post-read-more,.tool-cat-see-all{position:relative;}
.footer-link:after,.post-read-more:after,.tool-cat-see-all:after{
  content:'';position:absolute;left:0;bottom:-2px;width:0;height:1px;background:currentColor;transition:width var(--motion-base) var(--ease-pro);
}
.footer-link:hover:after,.post-read-more:hover:after,.tool-cat-see-all:hover:after{width:100%;}
.reveal-on-scroll{opacity:0;transform:translateY(26px) scale(.985);transition:opacity .7s var(--ease-pro),transform .7s var(--ease-pro);}
.reveal-on-scroll.is-visible{opacity:1;transform:translateY(0) scale(1);}
.reveal-stagger-1{transition-delay:.06s;}
.reveal-stagger-2{transition-delay:.12s;}
.reveal-stagger-3{transition-delay:.18s;}
.reveal-stagger-4{transition-delay:.24s;}
@keyframes floatSoft{0%,100%{transform:translateY(0)}50%{transform:translateY(-4px)}}
@keyframes glowPulse{0%,100%{box-shadow:0 0 0 0 rgba(59,130,246,.0)}50%{box-shadow:0 0 0 10px rgba(59,130,246,.08)}}
@media (prefers-reduced-motion: reduce){
  *,*::before,*::after{animation:none !important;transition:none !important;scroll-behavior:auto !important;}
  .reveal-on-scroll{opacity:1;transform:none;}
}

/* ===== LAYOUT SECTION WRAPPERS ===== */
.lp-section-wrap { width: 100%; }
.reveal-card{animation:fadeUp .6s both;}
.feature-card,.post-card,.cta-card{will-change:transform,box-shadow;}
.feature-card:hover,.post-card:hover,.tool-card:hover{transform:translateY(-4px);}
@media (max-width: 1024px) { .footer-grid { grid-template-columns: 1fr 1fr; gap: 32px; } .blog-layout { grid-template-columns: 1fr; } .sidebar { position: static; } }
@media (max-width: 768px) { .lp-nav { display: none; } .mobile-menu-btn { display: flex; } .tools-grid { grid-template-columns: repeat(2,1fr); } .features-grid { grid-template-columns: 1fr 1fr; } .hero-stats { gap: 20px; } .hero-stat-sep { display: none; } .cta-card { padding: 40px 24px; } .footer-grid { grid-template-columns: 1fr 1fr; } .footer-brand { grid-column: 1/-1; } .header-search { display: none; } }
@media (max-width: 480px) { .tools-grid { grid-template-columns: 1fr 1fr; gap: 8px; } .features-grid { grid-template-columns: 1fr; } .footer-grid { grid-template-columns: 1fr; } .hero-search-box { flex-direction: column; border-radius: 18px; padding: 12px 14px; gap: 8px; } .hero-search-btn { width: 100%; justify-content: center; } .cta-btns { flex-direction: column; align-items: center; } }
@media print { #lp-header, #lp-footer, .sidebar, .mobile-nav { display: none; } }
@keyframes ripple { to { transform: scale(2.5); opacity: 0; } }

body.script:
//
(function(){
  var s=localStorage.getItem('lp_theme')||'dark';
  if(s==='light')document.body.classList.add('light-mode');
  var btn=document.getElementById('theme-btn');
  if(btn)btn.textContent=s==='light'?'\u{1F319}':'\u2600\uFE0F';
})();
function toggleTheme(){
  var isLight=document.body.classList.toggle('light-mode');
  localStorage.setItem('lp_theme',isLight?'light':'dark');
  var btn=document.getElementById('theme-btn');
  if(btn)btn.textContent=isLight?'\u{1F319}':'\u2600\uFE0F';
}
function openMobileNav(){document.getElementById('mobile-nav').classList.add('open');document.body.style.overflow='hidden';}
function closeMobileNav(){document.getElementById('mobile-nav').classList.remove('open');document.body.style.overflow='';}
function openSearch(){
  document.getElementById('search-overlay').classList.add('open');
  setTimeout(function(){var inp=document.getElementById('search-overlay-input');if(inp)inp.focus();},150);
}
function closeSearch(){document.getElementById('search-overlay').classList.remove('open');}
function doSearch(){
  var v=document.getElementById('search-overlay-input').value.trim();
  if(v)window.location.href='/search?q='+encodeURIComponent(v);
}
function searchFor(term){
  var inp=document.getElementById('search-overlay-input');
  if(inp){inp.value=term;window.location.href='/search?q='+encodeURIComponent(term);}
}
document.addEventListener('keydown',function(e){
  if(e.key==='Escape'){closeSearch();closeMobileNav();}
  if((e.ctrlKey||e.metaKey)&&e.key==='k'){e.preventDefault();openSearch();}
});
function heroSearch(){
  var v=document.getElementById('hero-search').value.trim();
  if(v)window.location.href='/search?q='+encodeURIComponent(v);
}
window.addEventListener('scroll',function(){
  var h=document.getElementById('lp-header');
  if(!h)return;
  h.style.boxShadow=window.scrollY>20?'0 4px 24px rgba(0,0,0,.35)':'none';
},{passive:true});
var fy=document.getElementById('footer-year');
if(fy)fy.textContent=new Date().getFullYear();
document.querySelectorAll('a[href^="#"]').forEach(function(a){
  a.addEventListener('click',function(e){
    var t=document.querySelector(this.getAttribute('href'));
    if(t){e.preventDefault();t.scrollIntoView({behavior:'smooth',block:'start'});}
  });
});
document.querySelectorAll('.tool-card').forEach(function(card){
  card.addEventListener('click',function(e){
    var r=document.createElement('span');
    var rect=card.getBoundingClientRect();
    var size=Math.max(rect.width,rect.height);
    r.style.cssText='position:absolute;width:'+size+'px;height:'+size+'px;border-radius:50%;background:rgba(59,130,246,.15);transform:scale(0);animation:ripple .5s ease;top:'+(e.clientY-rect.top-size/2)+'px;left:'+(e.clientX-rect.left-size/2)+'px;pointer-events:none;z-index:0';
    card.style.position='relative';card.style.overflow='hidden';
    card.appendChild(r);
    setTimeout(function(){r.remove();},500);
  });
});
if('IntersectionObserver' in window){
  var io=new IntersectionObserver(function(entries){
    entries.forEach(function(e){
      if(e.isIntersecting){var img=e.target;if(img.dataset.src){img.src=img.dataset.src;io.unobserve(img);}}
    });
  });
  document.querySelectorAll('img[data-src]').forEach(function(img){io.observe(img);});
}
//

//
(function(){
  var d=document, w=window;
  function onScrollHeader(){
    var h=d.getElementById('lp-header');
    if(!h) return;
    if(w.scrollY > 12){h.classList.add('is-scrolled');}else{h.classList.remove('is-scrolled');}
  }
  function revealInit(){
    if(!('IntersectionObserver' in w)){
      d.querySelectorAll('.reveal-on-scroll').forEach(function(el){el.classList.add('is-visible');});
      return;
    }
    var io=new IntersectionObserver(function(entries){
      entries.forEach(function(entry){
        if(entry.isIntersecting){
          entry.target.classList.add('is-visible');
          io.unobserve(entry.target);
        }
      });
    },{threshold:.14,rootMargin:'0px 0px -40px 0px'});
    d.querySelectorAll('.reveal-on-scroll').forEach(function(el){io.observe(el);});
  }
  d.addEventListener('DOMContentLoaded', function(){
    onScrollHeader();
    revealInit();
  });
  w.addEventListener('scroll', onScrollHeader, {passive:true});
})();
//
